import pickle
import streamlit as st
import pandas as pd

Data=pickle.load(open(r'C:\Users\7y6t5\Desktop\diabetes project\Diabetes_prediction.sav','rb'))

st.title('Diabetes Prediction web app')
st.info('Easy Application for diabetes Prediction Disease')
st.sidebar.header('feature selection')


Pregnancies=st. text_input('Pregnancies')
Glucose=st. text_input ('Glucose')
BloodPressure=st. text_input('BloodPressure')
SkinThickness=st.text_input('SkinThickness')
BMI=st. text_input('BMI')
DiabetesPedigreeFunction=st. text_input('DiabetesPedigreeFunction')
Age=st. text_input('Age')

df=pd. DataFrame ({'Pregnancies': [Pregnancies], "Glucose": [Glucose], 'BloodPressure': [BloodPressure],
'SkinThickness': [SkinThickness], 'BMI': [BMI],'DiabetesPedigreeFunction': [DiabetesPedigreeFunction],
"Age": [Age]}, index=[0])
Con=st.sidebar.button('predict')
if Con:
    result=Data.predict (df)
    if result==0:
        st. sidebar. write('the patient is clear')
        st.sidebar.image('data:image/jpeg;base64,',width=200)
    else:
        st. sidebar. write('the patient has diabetes')  
        st.sidebar.image('data:image/jpeg;base64,',width=200)

    